def gen(rng, size):
    # bound the depth so the grid stays manageable (n up to 2^11-1)
    max_depth = 8
    class N:
        __slots__ = ('v', 'l', 'r')
        def __init__(self, v):
            self.v = v; self.l = None; self.r = None
    def build(depth):
        if depth >= max_depth:
            return None
        if depth > 0 and rng.random() < 0.3:
            return None
        node = N(rng.randint(-99, 99))
        node.l = build(depth + 1)
        node.r = build(depth + 1)
        return node
    root = build(0)
    if root is None:
        root = N(rng.randint(-99, 99))
    out = []
    q = [root]
    while q:
        node = q.pop(0)
        if node is None:
            out.append(None)
            continue
        out.append(node.v)
        q.append(node.l)
        q.append(node.r)
    while out and out[-1] is None:
        out.pop()
    return [out]

