class Solution:
    def printTree(self, root):
        def height(n):
            if not n:
                return -1
            return 1 + max(height(n.left), height(n.right))
        h = height(root)
        m = h + 1
        n = (1 << (h + 1)) - 1
        res = [['' for _ in range(n)] for _ in range(m)]
        nodes = [(root, 0, (n - 1) // 2)]
        while nodes:
            node, r, c = nodes.pop()
            if node is None:
                continue
            res[r][c] = str(node.val)
            gap = 1 << (h - r - 1) if h - r - 1 >= 0 else 0
            if node.left:
                nodes.append((node.left, r + 1, c - gap))
            if node.right:
                nodes.append((node.right, r + 1, c + gap))
        return res

