var printTree = function(root) {
    function height(n) {
        if (!n) return -1;
        return 1 + Math.max(height(n.left), height(n.right));
    }
    const h = height(root);
    const m = h + 1;
    const n = (1 << (h + 1)) - 1;
    const res = [];
    for (let i = 0; i < m; i++) {
        res.push(new Array(n).fill(''));
    }
    function place(node, r, c) {
        if (!node) return;
        res[r][c] = String(node.val);
        const offset = (h - r - 1) >= 0 ? (1 << (h - r - 1)) : 0;
        place(node.left, r + 1, c - offset);
        place(node.right, r + 1, c + offset);
    }
    place(root, 0, (n - 1) >> 1);
    return res;
};
